(window.webpackJsonp=window.webpackJsonp||[]).push([[120],{747:function(n,r){n.exports='\x3c!-- \r\ntitle: 04-串并互转\r\nsort: \r\n--\x3e \r\n# 串口与并口相互转换\r\n\r\n## 74HC165(并转串)\r\n\r\n```c\r\n#include "reg51.h"\r\n#include "intrins.h"\r\n\r\ntypedef unsigned char u8;\r\ntypedef unsigned int u16;\r\n\r\n#define GPIO_LED P0\r\n\r\nsbit IN_PL=P1^6;\r\nsbit IN_Data=P1^7;\r\nsbit SCK=P3^6;\r\n\r\nu8 Read165()\r\n{\r\n\tu8 indata = 0;\r\n\tu8 i;\r\n\t\r\n\tIN_PL = 0;\r\n\t_nop_();\r\n\tIN_PL = 1;\r\n\t_nop_();\r\n\tfor(i=0;i<8;i++)\r\n\t{\r\n\t\tindata = indata<<1;\r\n\t\tSCK = 0;\r\n\t\t_nop_();\r\n\t\t\r\n\t\tindata |= IN_Data ;\r\n\t\tSCK = 1;\r\n\t}\r\n\treturn indata;\r\n}\r\n\r\n\r\nvoid main()\r\n{\r\n\tu8 value165;\r\n\tGPIO_LED = 0;\r\n\twhile(1)\r\n\t{\r\n\t\tvalue165=Read165();\r\n\t\tif(value165!=0xff)\r\n\t\t{\r\n\t\t\tGPIO_LED = ~value165;\r\n\t\t}\r\n\t}\r\n}\r\n```\r\n\r\n## 74HC595(串转并)\r\n\r\n```c\r\n#include "reg51.h"\r\n#include "intrins.h"\r\n\r\ntypedef unsigned char u8;\r\ntypedef unsigned int u16;\r\n\r\n#define GPIO_LED P0\r\n\r\nsbit SRCLK=P3^6;\r\nsbit RCLK=P3^5;\r\nsbit SCK=P3^4;\r\n\r\nvoid delay(u16 i)\r\n{\r\n\twhile(i--);\r\n}\r\n\r\n\r\nvoid hc595(u8 dat)\r\n{\r\n\tu8 a;\r\n\tfor(a=0;a<8;a++)\r\n\t{\r\n\t\tSCK = dat>>7;\t//右移获取最高位\r\n\t\tdat<<=1;\t\t//左移删掉以传输的数据\r\n\t\t\r\n\t\tSRCLK = 0;\r\n\t\t_nop_();\r\n\t\t_nop_();\r\n\t\tSRCLK = 1;\r\n\t}\r\n\tRCLK = 0;\r\n\t_nop_();\r\n\t_nop_();\r\n\tRCLK = 1;\r\n}\r\n\r\n\r\nvoid main()\r\n{\r\n\tu8 ledNum;\r\n\tledNum = 0x01;\r\n\twhile(1)\r\n\t{\r\n\t\thc595(ledNum);\r\n\t\tledNum = _crol_(ledNum,1);\r\n\t\tdelay(50000);\r\n\t}\r\n}\r\n```\r\n\r\n'}}]);